import json
from collections import defaultdict
import re
import math

def tokenize(text):
    return re.findall(r"\w+", text.lower())

def compute_tfidf(posts):
    # Compute term frequency
    tf = []
    doc_freq = defaultdict(int)

    for post in posts:
        tokens = tokenize(post.get("content", ""))
        term_count = defaultdict(int)
        for token in tokens:
            term_count[token] += 1
            doc_freq[token] += 1
        tf.append(term_count)

    # Compute TF-IDF
    n_docs = len(posts)
    tfidf_vectors = []

    for term_count in tf:
        tfidf = {}
        for term, count in term_count.items():
            tf_score = count / sum(term_count.values())
            idf_score = math.log(n_docs / doc_freq[term])
            tfidf[term] = tf_score * idf_score
        tfidf_vectors.append(tfidf)

    return tfidf_vectors

def cosine_similarity(vec1, vec2):
    all_terms = set(vec1.keys()) | set(vec2.keys())
    dot_product = sum(vec1.get(term, 0) * vec2.get(term, 0) for term in all_terms)
    mag1 = math.sqrt(sum(v**2 for v in vec1.values()))
    mag2 = math.sqrt(sum(v**2 for v in vec2.values()))
    if mag1 == 0 or mag2 == 0:
        return 0
    return dot_product / (mag1 * mag2)

def cluster_posts(posts, threshold=0.3):
    tfidf_vectors = compute_tfidf(posts)
    clusters = []
    assigned = [False] * len(posts)

    for i in range(len(posts)):
        if assigned[i]:
            continue

        cluster = [i]
        assigned[i] = True

        for j in range(i + 1, len(posts)):
            if assigned[j]:
                continue

            similarity = cosine_similarity(tfidf_vectors[i], tfidf_vectors[j])
            if similarity >= threshold:
                cluster.append(j)
                assigned[j] = True

        clusters.append(cluster)

    return clusters

def extract_theme(posts, indices, tfidf_vectors):
    # Aggregate TF-IDF scores across cluster
    theme_scores = defaultdict(float)
    for idx in indices:
        for term, score in tfidf_vectors[idx].items():
            theme_scores[term] += score

    # Get top terms
    top_terms = sorted(theme_scores.items(), key=lambda x: x[1], reverse=True)[:5]
    return " ".join([term for term, _ in top_terms])

