if isinstance(posts_data, str):
    posts_data = json.loads(posts_data)

if not isinstance(posts_data, list):
    posts_data = [posts_data]

tfidf_vectors = compute_tfidf(posts_data)
clusters = cluster_posts(posts_data, threshold=0.3)

results = []
for cluster_id, indices in enumerate(clusters):
    if len(indices) >= 2:  # Only report clusters with 2+ posts
        theme = extract_theme(posts_data, indices, tfidf_vectors)

        # Calculate coherence (avg pairwise similarity)
        similarities = []
        for i in range(len(indices)):
            for j in range(i + 1, len(indices)):
                sim = cosine_similarity(tfidf_vectors[indices[i]], tfidf_vectors[indices[j]])
                similarities.append(sim)

        coherence = sum(similarities) / len(similarities) if similarities else 0

        results.append({
            "cluster_id": f"cluster_{cluster_id}",
            "theme": theme,
            "post_count": len(indices),
            "semantic_coherence": round(coherence, 3),
            "post_indices": indices
        })

return json.dumps({"clusters": results, "total_clusters": len(results)})

import json
from collections import defaultdict, deque
from datetime import datetime

def parse_timestamp(ts):
    try:
        if isinstance(ts, str):
            return datetime.fromisoformat(ts.replace("Z", "+00:00"))
        return ts
    except:
        return datetime.now()

def build_propagation_graph(posts):
    # Build graph of repost relationships
    graph = defaultdict(list)
    post_times = {}

    for post in posts:
        post_id = post.get("id", post.get("post_id"))
        parent_id = post.get("repost_of", post.get("parent_id"))
        timestamp = parse_timestamp(post.get("timestamp", post.get("created_at")))

        post_times[post_id] = timestamp

        if parent_id:
            graph[parent_id].append(post_id)

    return graph, post_times

def analyze_cascade(origin_id, graph, post_times):
    # BFS to measure cascade depth and velocity
    queue = deque([(origin_id, 0)])  # (post_id, depth)
    visited = {origin_id}
    max_depth = 0
    cascade_posts = [origin_id]

    while queue:
        current_id, depth = queue.popleft()
        max_depth = max(max_depth, depth)

        for child_id in graph.get(current_id, []):
            if child_id not in visited:
                visited.add(child_id)
                cascade_posts.append(child_id)
                queue.append((child_id, depth + 1))

    # Calculate spread velocity (posts per hour)
    if len(cascade_posts) > 1:
        timestamps = [post_times[pid] for pid in cascade_posts if pid in post_times]
        if len(timestamps) > 1:
            time_span = (max(timestamps) - min(timestamps)).total_seconds() / 3600  # hours
            velocity = len(cascade_posts) / max(time_span, 0.1)
        else:
            velocity = 0
    else:
        velocity = 0

    return {
        "cascade_id": f"cascade_{origin_id}",
        "origin_post": origin_id,
        "total_posts": len(cascade_posts),
        "network_depth": max_depth,
        "spread_velocity": round(velocity, 2)
    }

