import json
from collections import defaultdict

def generate_risk_heatmap(narrative_data, bot_data):
    # Parse inputs
    if isinstance(narrative_data, str):
        narrative_data = json.loads(narrative_data)
    if isinstance(bot_data, str):
        bot_data = json.loads(bot_data)

    # Extract high-risk topics from narrative clusters
    high_risk_topics = []
    topic_attention = {}

    if "clusters" in narrative_data:
        for cluster in narrative_data["clusters"]:
            theme = cluster.get("theme", "")
            coherence = cluster.get("semantic_coherence", 0)
            post_count = cluster.get("post_count", 0)

            # Risk score based on coherence (coordination) and volume
            risk_score = (coherence * 0.6) + (min(post_count / 50, 1.0) * 0.4)

            if risk_score > 0.5:
                high_risk_topics.append(theme)
                topic_attention[theme] = {
                    "risk_score": round(risk_score, 3),
                    "coherence_weight": round(coherence * 0.6, 3),
                    "volume_weight": round(min(post_count / 50, 1.0) * 0.4, 3),
                    "post_count": post_count
                }

    # Extract high-risk accounts from bot signatures
    high_risk_accounts = []
    account_attention = {}

    if "bot_signatures" in bot_data:
        for signature in bot_data["bot_signatures"]:
            account_id = signature.get("account_id", "")
            bot_prob = signature.get("bot_probability", 0)
            patterns = signature.get("behavioral_patterns", [])

            if bot_prob > 0.5:
                high_risk_accounts.append(account_id)

                # Attention weights for explainability
                pattern_weights = {}
                for pattern in patterns:
                    if pattern == "low_interval_variance":
                        pattern_weights[pattern] = 0.25
                    elif pattern == "burst_posting":
                        pattern_weights[pattern] = 0.25
                    elif pattern == "regular_intervals":
                        pattern_weights[pattern] = 0.25
                    elif pattern == "24_7_activity":
                        pattern_weights[pattern] = 0.25
                    elif pattern == "high_frequency":
                        pattern_weights[pattern] = 0.15

                account_attention[account_id] = {
                    "bot_probability": bot_prob,
                    "pattern_weights": pattern_weights,
                    "total_patterns": len(patterns)
                }

    # Generate explainability summary
    explainability = []

    if high_risk_topics:
        explainability.append(f"Identified {len(high_risk_topics)} coordinated narrative clusters with high semantic coherence, indicating potential information operations.")

    if high_risk_accounts:
        explainability.append(f"Detected {len(high_risk_accounts)} accounts with bot-like behavioral signatures based on temporal activity patterns.")

    # Attention-based reasoning
    explainability.append("Risk assessment uses attention weights: narrative coherence (60%), post volume (40%), and bot behavioral patterns (temporal regularity, burst activity, 24/7 posting).")

    return {
        "high_risk_topics": high_risk_topics[:10],
        "high_risk_accounts": high_risk_accounts[:20],
        "attention_weights": {
            "topics": topic_attention,
            "accounts": account_attention
        },
        "explainability": " ".join(explainability),
        "summary": {
            "total_risk_topics": len(high_risk_topics),
            "total_risk_accounts": len(high_risk_accounts)
        }
    }

# Main execution
narrative_results = $fromAI("narrative_analysis", "Results from narrative pattern detection including clusters", "object")
bot_results = $fromAI("bot_analysis", "Results from bot behavior analysis including signatures", "object")

heatmap = generate_risk_heatmap(narrative_results, bot_results)

return json.dumps(heatmap)

import json
import re

def classify_manipulation_techniques(text):
    if not text:
        return {"techniques": [], "confidence": 0}

    text_lower = text.lower()
    detected_techniques = []

    # Emotional manipulation patterns
    emotional_patterns = {
        "fear_appeal": ["danger", "threat", "risk", "unsafe", "scary", "terrifying", "alarming"],
        "outrage_generation": ["outrageous", "unbelievable", "shocking", "disgusting", "appalling"],
        "moral_panic": ["destroying", "ruining", "corrupting", "threatening our way"],
        "emotional_appeal": ["heartbreaking", "tragic", "devastating", "touching"]
    }

    for technique, keywords in emotional_patterns.items():
        if any(keyword in text_lower for keyword in keywords):
            detected_techniques.append({
                "category": "emotional_manipulation",
                "technique": technique,
                "confidence": 0.7,
                "explanation": f"Uses {technique.replace('_', ' ')} to evoke strong emotional response"
            })

    # Logical fallacy patterns
    fallacy_patterns = {
        "strawman": ["they claim", "they say", "they want you to believe"],
        "false_equivalence": ["just as bad as", "no different than", "same as"],
        "slippery_slope": ["next thing", "before you know it", "lead to", "will result in"],
        "ad_hominem": ["hypocrite", "liar", "corrupt", "dishonest"]
    }

    for technique, keywords in fallacy_patterns.items():
        if any(keyword in text_lower for keyword in keywords):
            detected_techniques.append({
                "category": "logical_fallacy",
                "technique": technique,
                "confidence": 0.6,
                "explanation": f"Employs {technique.replace('_', ' ')} fallacy to mislead reasoning"
            })

    # Propaganda techniques
    propaganda_patterns = {
        "bandwagon": ["everyone", "everybody", "most people", "join us", "be part of"],
        "glittering_generalities": ["freedom", "liberty", "justice", "truth", "patriot"],
        "name_calling": ["elite", "establishment", "mainstream", "radical"],
        "transfer": ["our values", "our heritage", "our tradition"]
    }

    for technique, keywords in propaganda_patterns.items():
        if any(keyword in text_lower for keyword in keywords):
            detected_techniques.append({
                "category": "propaganda",
                "technique": technique,
                "confidence": 0.65,
                "explanation": f"Uses {technique.replace('_', ' ')} propaganda technique"
            })

    # Disinformation tactics
    disinfo_patterns = {
        "cherry_picking": ["studies show", "research proves", "experts say"],
        "misleading_statistics": [r"\d+%", r"\d+ times", "increase of"],
        "out_of_context": ["quote", "said", "stated", "according to"]
    }

    for technique, patterns in disinfo_patterns.items():
        for pattern in patterns:
            if re.search(pattern, text_lower):
                detected_techniques.append({
                    "category": "disinformation_tactic",
                    "technique": technique,
                    "confidence": 0.5,
                    "explanation": f"Potential {technique.replace('_', ' ')} detected"
                })
                break

    # Calculate overall manipulation score
    if detected_techniques:
        avg_confidence = sum(t["confidence"] for t in detected_techniques) / len(detected_techniques)
        manipulation_score = min(len(detected_techniques) * 0.15, 1.0)
    else:
        avg_confidence = 0
        manipulation_score = 0

    return {
        "techniques": detected_techniques,
        "total_techniques": len(detected_techniques),
        "manipulation_score": round(manipulation_score, 3),
        "avg_confidence": round(avg_confidence, 3)
    }

# Main execution
content = $fromAI("text", "Text content to analyze for manipulation techniques", "string")

result = classify_manipulation_techniques(content)

return json.dumps(result)
